import{_ as a,o as r,c as i,S as e}from"./chunks/framework.C6RQlTYc.js";const c=JSON.parse('{"title":"RLHF 与对齐训练","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_15-rlhf.md","filePath":"直击概念/17ai/s_ai_15-rlhf.md","lastUpdated":1778207238000}'),l={name:"直击概念/17ai/s_ai_15-rlhf.md"};function o(n,t,d,s,h,u){return r(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="rlhf-与对齐训练" tabindex="-1">RLHF 与对齐训练 <a class="header-anchor" href="#rlhf-与对齐训练" aria-label="Permalink to &quot;RLHF 与对齐训练&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>RLHF（Reinforcement Learning from Human Feedback，基于人类反馈的强化学习）是将 LLM 的<strong>输出与人类偏好对齐</strong>的关键技术。预训练使模型&quot;有知识&quot;，RLHF 使模型&quot;会做人&quot;——确保回答有用、诚实、无害。</p><p>如果没有对齐训练，LLM 会像一部续写机器，而不是能遵循指令和价值观的助手。</p><h2 id="为什么需要对齐" tabindex="-1">为什么需要对齐 <a class="header-anchor" href="#为什么需要对齐" aria-label="Permalink to &quot;为什么需要对齐&quot;">​</a></h2><p>预训练模型的问题：</p><ul><li><strong>不会对话</strong>：只会续写文本，不会回答提问</li><li><strong>有害输出</strong>：可能生成不当或危险内容</li><li><strong>编造事实</strong>：预训练阶段不管事实正确性</li><li><strong>无法拒绝</strong>：即使不知道也会强行回答</li></ul><p>对齐训练的目标是让模型实现 <strong>HHH 原则</strong>：</p><ul><li><strong>Helpful（有帮助）</strong></li><li><strong>Honest（诚实）</strong></li><li><strong>Harmless（无害）</strong></li></ul><h2 id="三阶段对齐流程" tabindex="-1">三阶段对齐流程 <a class="header-anchor" href="#三阶段对齐流程" aria-label="Permalink to &quot;三阶段对齐流程&quot;">​</a></h2><h3 id="阶段一-sft-supervised-fine-tuning-监督微调" tabindex="-1">阶段一：SFT（Supervised Fine-Tuning，监督微调） <a class="header-anchor" href="#阶段一-sft-supervised-fine-tuning-监督微调" aria-label="Permalink to &quot;阶段一：SFT（Supervised Fine-Tuning，监督微调）&quot;">​</a></h3><p>用高质量人工编写的<strong>指令-回答对</strong>训练模型：</p><ul><li>数据来自专业标注人员</li><li>让模型学会&quot;对话格式&quot;和基本指令遵循</li><li>数据量通常数千到数万条</li></ul><h3 id="阶段二-rm-reward-model-奖励模型训练" tabindex="-1">阶段二：RM（Reward Model，奖励模型训练） <a class="header-anchor" href="#阶段二-rm-reward-model-奖励模型训练" aria-label="Permalink to &quot;阶段二：RM（Reward Model，奖励模型训练）&quot;">​</a></h3><ol><li>让 SFT 后的模型对同一条 prompt 生成多个回答</li><li>人工标注员对这些回答<strong>排序</strong>（A &gt; B &gt; C）</li><li>用排序数据训练一个奖励模型，学会预测&quot;人类更偏好哪个回答&quot;</li></ol><h3 id="阶段三-ppo-proximal-policy-optimization" tabindex="-1">阶段三：PPO（Proximal Policy Optimization） <a class="header-anchor" href="#阶段三-ppo-proximal-policy-optimization" aria-label="Permalink to &quot;阶段三：PPO（Proximal Policy Optimization）&quot;">​</a></h3><p>用强化学习进一步优化模型：</p><ol><li>LLM 生成回答</li><li>RM（奖励模型）打分</li><li>通过 PPO 算法更新 LLM 参数以最大化奖励</li><li>同时约束新策略不要偏离 SFT 模型太远（KL 散度约束）</li></ol><h2 id="dpo-vs-rlhf" tabindex="-1">DPO vs RLHF <a class="header-anchor" href="#dpo-vs-rlhf" aria-label="Permalink to &quot;DPO vs RLHF&quot;">​</a></h2><p>DPO（Direct Preference Optimization）是一种<strong>不需要训练奖励模型</strong>的对齐方法：</p><table><thead><tr><th>维度</th><th>RLHF（PPO）</th><th>DPO</th></tr></thead><tbody><tr><td>是否需要奖励模型</td><td>是</td><td>否</td></tr><tr><td>训练复杂度</td><td>高（四模型交互）</td><td>低（直接优化）</td></tr><tr><td>训练稳定性</td><td>需调参</td><td>较稳定</td></tr><tr><td>使用</td><td>ChatGPT、Claude</td><td>Llama 3、Mistral</td></tr></tbody></table><p>DPO 直接从偏好数据优化策略，把 RLHF 的三阶段简化为两阶段。</p><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>为什么 LLM 需要对人类偏好对齐？不这么做会怎样？</li><li>RLHF 的三个阶段各是什么？DPO 简化了什么？</li><li>对齐训练可能带来哪些副作用（如过度拒绝、政治偏见等）？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2203.02155" target="_blank" rel="noreferrer">Training language models to follow instructions with human feedback</a></li><li><a href="https://arxiv.org/abs/2305.18290" target="_blank" rel="noreferrer">DPO: Direct Preference Optimization</a></li></ul>',26)])])}const f=a(l,[["render",o]]);export{c as __pageData,f as default};
